\displaystyle{\begin{aligned}[t]
    \frac{4}{25} \div \left(-\frac{3}{10}\right)
        \amp = \frac{4}{25} \cdot \left(-\frac{10}{3}\right) \amp \hbox{We can divide the first denominator and the second numerator by 5.}\\
        \amp = \frac{4}{5 }\cdot\left(-\frac{2}{3}\right) \\
        \amp = -\frac{8}{15}
\end{aligned}
    }
